// Calculate this week (Mon-Sun) and previous week date ranges
const now = new Date();
const today = now.toISOString().split('T')[0];

// This week: last Monday to today
const dayOfWeek = now.getDay(); // 0=Sun, 1=Mon
const daysSinceMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const thisWeekStart = new Date(now.getTime() - daysSinceMonday * 24 * 60 * 60 * 1000);
const thisWeekStartStr = thisWeekStart.toISOString().split('T')[0];

// Previous week: Monday to Sunday before this week
const prevWeekStart = new Date(thisWeekStart.getTime() - 7 * 24 * 60 * 60 * 1000);
const prevWeekEnd = new Date(thisWeekStart.getTime() - 1 * 24 * 60 * 60 * 1000);
const prevWeekStartStr = prevWeekStart.toISOString().split('T')[0];
const prevWeekEndStr = prevWeekEnd.toISOString().split('T')[0];

return [{ json: {
  today,
  thisWeekStart: thisWeekStartStr,
  prevWeekStart: prevWeekStartStr,
  prevWeekEnd: prevWeekEndStr,
  nowIso: now.toISOString()
} }];

// Aggregate ad performance by campaign with week-over-week comparison
const thisWeekResponse = $('Fetch This Week Ads').first().json;
const prevWeekResponse = $('Fetch Previous Week Ads').first().json;
const alertsResponse = $('Fetch Ads Alerts').first().json;
const dates = $('Calculate Week Ranges').first().json;

const thisWeekData = thisWeekResponse.body || thisWeekResponse || [];
const prevWeekData = prevWeekResponse.body || prevWeekResponse || [];
const alertsData = alertsResponse.body || alertsResponse || [];

// Aggregate by campaign
function aggregateByCampaign(rows) {
  const campaigns = {};
  if (!Array.isArray(rows)) return campaigns;
  for (const row of rows) {
    const name = row.campaign_name || 'Unknown';
    if (!campaigns[name]) {
      campaigns[name] = { impressions: 0, clicks: 0, conversions: 0, cost: 0, days: 0 };
    }
    campaigns[name].impressions += parseFloat(row.impressions) || 0;
    campaigns[name].clicks += parseFloat(row.clicks) || 0;
    campaigns[name].conversions += parseFloat(row.conversions) || 0;
    campaigns[name].cost += parseFloat(row.cost) || 0;
    campaigns[name].days += 1;
  }
  // Calculate derived metrics
  for (const [name, c] of Object.entries(campaigns)) {
    c.cpc = c.clicks > 0 ? c.cost / c.clicks : 0;
    c.ctr = c.impressions > 0 ? (c.clicks / c.impressions) * 100 : 0;
    c.conversion_rate = c.clicks > 0 ? (c.conversions / c.clicks) * 100 : 0;
    c.roas = c.cost > 0 ? (c.conversions * 150) / c.cost : 0; // Estimate $150/conversion
    c.cost_per_conversion = c.conversions > 0 ? c.cost / c.conversions : 0;
  }
  return campaigns;
}

const thisWeekCampaigns = aggregateByCampaign(thisWeekData);
const prevWeekCampaigns = aggregateByCampaign(prevWeekData);

// Totals
function sumCampaigns(campaigns) {
  const total = { impressions: 0, clicks: 0, conversions: 0, cost: 0 };
  for (const c of Object.values(campaigns)) {
    total.impressions += c.impressions;
    total.clicks += c.clicks;
    total.conversions += c.conversions;
    total.cost += c.cost;
  }
  total.cpc = total.clicks > 0 ? total.cost / total.clicks : 0;
  total.ctr = total.impressions > 0 ? (total.clicks / total.impressions) * 100 : 0;
  total.conversion_rate = total.clicks > 0 ? (total.conversions / total.clicks) * 100 : 0;
  total.roas = total.cost > 0 ? (total.conversions * 150) / total.cost : 0;
  total.cost_per_conversion = total.conversions > 0 ? total.cost / total.conversions : 0;
  return total;
}

const thisTotal = sumCampaigns(thisWeekCampaigns);
const prevTotal = sumCampaigns(prevWeekCampaigns);

// Week-over-week change helper
function wow(current, previous) {
  if (previous === 0) return current > 0 ? '+100%' : '—';
  const pct = ((current - previous) / Math.abs(previous)) * 100;
  const sign = pct >= 0 ? '+' : '';
  return `${sign}${pct.toFixed(1)}%`;
}

function fmt(n, decimals) {
  if (decimals === undefined) decimals = 0;
  return n.toLocaleString('en-US', { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
}

// Build TG-118 sections
const metrics = [
  { label: 'Total Spend', value: `$${fmt(thisTotal.cost, 2)}`, change: wow(thisTotal.cost, prevTotal.cost) },
  { label: 'Conversions', value: fmt(thisTotal.conversions), change: wow(thisTotal.conversions, prevTotal.conversions) },
  { label: 'Cost/Conv', value: thisTotal.cost_per_conversion > 0 ? `$${fmt(thisTotal.cost_per_conversion, 2)}` : '—', change: thisTotal.cost_per_conversion > 0 && prevTotal.cost_per_conversion > 0 ? wow(thisTotal.cost_per_conversion, prevTotal.cost_per_conversion) : '' },
  { label: 'ROAS', value: `${fmt(thisTotal.roas, 2)}x`, change: wow(thisTotal.roas, prevTotal.roas) }
];

// Campaign table
const campaignNames = [...new Set([...Object.keys(thisWeekCampaigns), ...Object.keys(prevWeekCampaigns)])];
const tableHeaders = ['Campaign', 'Spend', 'Clicks', 'Conv', 'CPC', 'ROAS', 'WoW Spend'];
const tableRows = campaignNames.map(name => {
  const tw = thisWeekCampaigns[name] || { cost: 0, clicks: 0, conversions: 0, cpc: 0, roas: 0 };
  const pw = prevWeekCampaigns[name] || { cost: 0 };
  return [
    name,
    `$${fmt(tw.cost, 2)}`,
    fmt(tw.clicks),
    fmt(tw.conversions),
    `$${fmt(tw.cpc, 2)}`,
    `${fmt(tw.roas, 2)}x`,
    wow(tw.cost, pw.cost)
  ];
});

// Highlights
const highlights = [];
if (thisTotal.conversions > prevTotal.conversions) {
  highlights.push(`Conversions up ${wow(thisTotal.conversions, prevTotal.conversions)} week-over-week (${fmt(prevTotal.conversions)} -> ${fmt(thisTotal.conversions)})`);
}
if (thisTotal.cost_per_conversion > 0 && thisTotal.cost_per_conversion < prevTotal.cost_per_conversion) {
  highlights.push(`Cost per conversion improved to $${fmt(thisTotal.cost_per_conversion, 2)} (was $${fmt(prevTotal.cost_per_conversion, 2)})`);
}
const bestCampaign = Object.entries(thisWeekCampaigns).sort((a, b) => b[1].conversions - a[1].conversions)[0];
if (bestCampaign && bestCampaign[1].conversions > 0) {
  highlights.push(`Top campaign: ${bestCampaign[0]} with ${fmt(bestCampaign[1].conversions)} conversions at $${fmt(bestCampaign[1].cost_per_conversion, 2)}/conv`);
}
if (highlights.length === 0) {
  highlights.push(`Total spend: $${fmt(thisTotal.cost, 2)} across ${campaignNames.length} campaign(s)`);
}

// Anomalies from alerts
const anomalyItems = Array.isArray(alertsData) ? alertsData.map(a => ({
  severity: a.severity || 'warning',
  message: a.alert_message || a.description || `${a.alert_type}: ${a.campaign_name || 'Unknown campaign'}`
})) : [];

// Actions
const actions = [];
if (thisTotal.cost_per_conversion > 100) {
  actions.push(`Review high cost/conversion ($${fmt(thisTotal.cost_per_conversion, 2)}) — consider pausing underperforming campaigns`);
}
if (thisTotal.roas < 1) {
  actions.push(`ROAS below 1x ($${fmt(thisTotal.roas, 2)}x) — ad spend exceeding estimated return`);
}
const lowConvCampaigns = Object.entries(thisWeekCampaigns).filter(([_, c]) => c.cost > 50 && c.conversions === 0);
if (lowConvCampaigns.length > 0) {
  actions.push(`${lowConvCampaigns.length} campaign(s) with $50+ spend and 0 conversions: ${lowConvCampaigns.map(([n]) => n).join(', ')}`);
}
if (actions.length === 0) {
  actions.push('All campaigns performing within normal ranges — continue monitoring');
}

const sections = [
  { type: 'metrics', title: 'Weekly Ad Performance', items: metrics },
  { type: 'highlights', title: 'Highlights', items: highlights },
  { type: 'table', title: 'Campaign Breakdown', headers: tableHeaders, rows: tableRows },
];
if (anomalyItems.length > 0) {
  sections.push({ type: 'anomalies', title: 'Ad Alerts This Week', items: anomalyItems });
}
sections.push({ type: 'actions', title: 'Recommended Actions', items: actions });

return [{ json: {
  report_title: 'Weekly Ad Performance',
  report_subtitle: `${dates.thisWeekStart} to ${dates.today}`,
  sections,
  // For storage
  summary: {
    total_spend: thisTotal.cost,
    total_conversions: thisTotal.conversions,
    total_clicks: thisTotal.clicks,
    cost_per_conversion: thisTotal.cost_per_conversion,
    roas: thisTotal.roas,
    campaign_count: campaignNames.length,
    alerts_count: anomalyItems.length,
    week_start: dates.thisWeekStart,
    week_end: dates.today
  }
} }];

// No ads data this week — send brief notification
const dates = $('Calculate Week Ranges').first().json;

return [{ json: {
  report_title: 'Weekly Ad Performance',
  report_subtitle: `${dates.thisWeekStart} to ${dates.today}`,
  sections: [
    {
      type: 'highlights',
      title: 'No Ad Data This Week',
      items: [
        'No Google Ads data was recorded for this period.',
        'This could mean no campaigns are running, or the Google Ads API sync (TG-109) has not been configured yet.',
        'If campaigns are active, verify TG-109 is running and the Google Ads customer ID is set.'
      ]
    },
    {
      type: 'actions',
      title: 'Next Steps',
      items: [
        'Verify Google Ads account is active and campaigns are running',
        'Check that TG-109 daily sync is configured with $vars.TG_GOOGLE_ADS_CUSTOMER_ID',
        'Review Google Ads dashboard directly for any issues'
      ]
    }
  ],
  summary: {
    total_spend: 0,
    total_conversions: 0,
    total_clicks: 0,
    cost_per_conversion: 0,
    roas: 0,
    campaign_count: 0,
    alerts_count: 0,
    week_start: dates.thisWeekStart,
    week_end: dates.today,
    status: 'no_data'
  }
} }];
